{"query":"with users as (
  select distinct trim(both '{}' from digitalbankinguser_system_id) as sysid
  from dim.digitalbankinguser
), accts as (
  select distinct accountguid from dim.account
)
select count(*) as overlap
from users u
join accts a on upper(a.accountguid) = upper(u.sysid);"}
